});

await viewElement.viewOnReady();
viewElement.map?.add(featureLayer);

const params = {
  layer: featureLayer,
  field: "B17020_calc_pctPovE",
  view: viewElement.view,
};

const rendererResult = await colorAndSizeRendererCreator.createContinuousRenderer(params);

